section.code:
{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://faion.net/schemas/php-laravel-patterns.json",
  "type": "object",
  "required": ["controllers", "services", "uses_form_requests", "uses_json_resources", "uses_db_transaction_closure"],
  "properties": {
    "controllers": {
      "type": "array",
      "minItems": 1,
      "items": {
        "type": "object",
        "required": ["class", "contains_eloquent", "loc"],
        "properties": {
          "class": {"type": "string", "pattern": "Controller$"},
          "contains_eloquent": {"type": "boolean", "const": false},
          "loc": {"type": "integer", "maximum": 150}
        }
      }
    },
    "services": {
      "type": "array",
      "minItems": 1,
      "items": {
        "type": "object",
        "required": ["class", "uses_request_globals", "returns_jsonresponse"],
        "properties": {
          "class": {"type": "string", "pattern": "Service$"},
          "uses_request_globals": {"type": "boolean", "const": false},
          "returns_jsonresponse": {"type": "boolean", "const": false}
        }
      }
    },
    "uses_form_requests": {"type": "boolean", "const": true},
    "uses_json_resources": {"type": "boolean", "const": true},
    "uses_db_transaction_closure": {"type": "boolean", "const": true},
    "forbidden_patterns_found": {"type": "array", "items": {"type": "string"}, "maxItems": 0}
  }
}
